import React, { useState, useRef, useEffect } from 'react';
import { useSpring, animated } from '@react-spring/web';
import { 
  X, 
  ArrowLeft, 
  Send, 
  Paperclip, 
  Smile, 
  MoreHorizontal,
  Phone,
  Video,
  Info,
  Minus
} from 'lucide-react';

const ConversationPanel = ({ 
  conversation, 
  isVisible, 
  onClose, 
  onBack,
  messages = []
}) => {
  const [isMinimized, setIsMinimized] = useState(false);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  // Animação do painel
  const panelAnimation = useSpring({
    transform: isVisible ? 'translateY(0%)' : 'translateY(100%)',
    opacity: isVisible ? 1 : 0,
    config: { tension: 300, friction: 30 }
  });

  // Animação da altura (minimizado/expandido)
  const heightAnimation = useSpring({
    height: isMinimized ? '60px' : '400px',
    config: { tension: 300, friction: 30 }
  });

  // Scroll automático para a última mensagem
  useEffect(() => {
    if (messagesEndRef.current && !isMinimized) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isMinimized]);

  const handleSendMessage = () => {
    if (newMessage.trim()) {
      // Aqui você implementaria a lógica para enviar a mensagem
      console.log('Enviando mensagem:', newMessage);
      setNewMessage('');
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const toggleMinimize = () => {
    setIsMinimized(!isMinimized);
  };

  if (!isVisible || !conversation) return null;

  return (
    <div className="fixed bottom-4 right-[340px] z-50">
      <animated.div
        style={{
          ...panelAnimation,
          ...heightAnimation,
          width: '320px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-lg overflow-hidden"
      >
        {/* Header */}
        <div className="bg-neutral-900 px-4 py-3 flex items-center justify-between border-b border-neutral-700">
          <div className="flex items-center space-x-3">
            <button
              onClick={onBack}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <ArrowLeft className="h-4 w-4" />
            </button>
            <div className="relative">
              <img
                src={conversation.avatar}
                alt={conversation.name}
                className="w-8 h-8 rounded-full"
              />
              <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-900 ${
                conversation.status === 'online' ? 'bg-green-500' : 
                conversation.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
              }`} />
            </div>
            <div>
              <h3 className="text-white font-medium text-sm">{conversation.name}</h3>
              <p className="text-xs text-neutral-400">
                {conversation.status === 'online' ? 'Online' : 
                 conversation.status === 'away' ? 'Ausente' : 'Offline'}
              </p>
            </div>
          </div>
          <div className="flex items-center space-x-1">
            <button className="p-1 text-gray-400 hover:text-white transition-colors">
              <Phone className="h-4 w-4" />
            </button>
            <button className="p-1 text-gray-400 hover:text-white transition-colors">
              <Video className="h-4 w-4" />
            </button>
            <button
              onClick={toggleMinimize}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <Minus className="h-4 w-4" />
            </button>
            <button
              onClick={onClose}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <X className="h-4 w-4" />
            </button>
          </div>
        </div>

        {!isMinimized && (
          <>
            {/* Nudge Content Area */}
            <div className="flex-1 overflow-y-auto p-4 max-h-[280px] bg-neutral-800">
              {conversation && (
                <div className="space-y-4">
                  {/* Nudge Message */}
                  <div className="bg-neutral-700 rounded-lg p-4">
                    <div className="flex items-start space-x-3 mb-3">
                      <img
                        src={conversation.avatar}
                        alt={conversation.name}
                        className="w-8 h-8 rounded-full"
                      />
                      <div className="flex-1">
                        <h4 className="text-white font-medium">{conversation.name}</h4>
                        <p className="text-neutral-400 text-sm">{conversation.timestamp}</p>
                      </div>
                      {conversation.priority && (
                        <div className={`px-2 py-1 rounded-full text-xs font-medium ${
                          conversation.priority === 'high' 
                            ? 'bg-red-500/10 text-red-400 border border-red-500/20' 
                            : conversation.priority === 'normal'
                            ? 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
                            : 'bg-gray-500/10 text-gray-400 border border-gray-500/20'
                        }`}>
                          {conversation.priority === 'high' ? 'Alta' : 
                           conversation.priority === 'normal' ? 'Normal' : 'Baixa'}
                        </div>
                      )}
                    </div>
                    <p className="text-white text-sm leading-relaxed">
                      {conversation.fullMessage || conversation.lastMessage}
                    </p>

                    {/* Attachments */}
                    {conversation.attachments && conversation.attachments.length > 0 && (
                      <div className="mt-3 space-y-2">
                        <p className="text-neutral-400 text-xs font-medium">Anexos:</p>
                        {conversation.attachments.map((attachment, index) => (
                          <div key={index} className="flex items-center space-x-2 bg-neutral-600 rounded p-2">
                            <Paperclip className="h-4 w-4 text-neutral-400" />
                            <span className="text-white text-sm">{attachment}</span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Action Buttons */}
                  <div className="flex space-x-2">
                    <button className="flex-1 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                      Responder
                    </button>
                    <button className="flex-1 bg-neutral-700 hover:bg-neutral-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                      Não Posso
                    </button>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>


          </>
        )}
      </animated.div>
    </div>
  );
};

export default ConversationPanel;
